def borda_count(rank_matrix: dict) -> dict:
    """
    rank_matrix: {model_name: {benchmark: rank}}
    Returns {model_name: borda_score}, higher is better.
    """
    # number of models
    n = len(rank_matrix)
    borda = {}
    for model, ranks in rank_matrix.items():
        borda[model] = sum(n - r for r in ranks.values())
    return dict(sorted(borda.items(), key=lambda x: -x[1]))

ranks = {
    'model_A': {'mmlu': 2, 'hellaswag': 1, 'gpqa': 3},
    'model_B': {'mmlu': 1, 'hellaswag': 3, 'gpqa': 2},
    'model_C': {'mmlu': 3, 'hellaswag': 2, 'gpqa': 1},
}
print(borda_count(ranks))
# {'model_A': 7, 'model_B': 7, 'model_C': 7}  — three-way tie
# (each model is best on one benchmark and worst on one other)

from dataclasses import dataclass
import math

@dataclass
class EvalResult:
    model: str
    correct: int
    total: int

    @property
    def accuracy(self) -> float:
        return self.correct / self.total

    def ci_95(self) -> tuple[float, float]:
        z, n, p = 1.96, self.total, self.accuracy
        centre = (p + z**2/(2*n)) / (1 + z**2/n)
        half = z * math.sqrt(p*(1-p)/n + z**2/(4*n**2)) / (1 + z**2/n)
        return round(centre-half, 4), round(centre+half, 4)

    def __str__(self):
        lo, hi = self.ci_95()
        return (f'{self.model}: {self.accuracy:.3f} '
                f'(95% CI [{lo:.3f}, {hi:.3f}], n={self.total})')

results = [
    EvalResult('model_A', 168, 200),
    EvalResult('model_B', 172, 200),
    EvalResult('model_C', 160, 200),
]
for r in sorted(results, key=lambda x: -x.accuracy):
    print(r)
